table|accounting_variance|CREATE TABLE accounting_variance ( id INTEGER PRIMARY KEY AUTOINCREMENT, period_start TEXT, period_end TEXT, theoretical_cogs REAL, actual_cogs REAL, variance_amount REAL, variance_pct REAL, snapshot_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' , actual_cogs_breakdown_json TEXT)
table|allergen_attestations|CREATE TABLE allergen_attestations ( id INTEGER PRIMARY KEY AUTOINCREMENT, recipe_slug TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', allergens_json TEXT NOT NULL DEFAULT '[]', recipe_fingerprint TEXT NOT NULL, attested_by TEXT NOT NULL, note TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|audit_events|CREATE TABLE audit_events ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', actor_cook_id TEXT, actor_source TEXT NOT NULL, entity TEXT NOT NULL, entity_id INTEGER, action TEXT NOT NULL CHECK(action IN ('insert','update','delete','correction','view')), replaces_id INTEGER, payload_json TEXT, note TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|beo_courses|CREATE TABLE beo_courses ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', course_label TEXT NOT NULL, fire_at TEXT NOT NULL, notes TEXT, sort_order INTEGER DEFAULT 0, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), station_id TEXT, FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|beo_event_charges|CREATE TABLE beo_event_charges ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, kind TEXT NOT NULL, item_name TEXT NOT NULL, charge REAL NOT NULL DEFAULT 0, cost REAL NOT NULL DEFAULT 0, sort_order INTEGER DEFAULT 0, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|beo_events|CREATE TABLE beo_events ( id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT NOT NULL, event_date TEXT, event_time TEXT, contact_name TEXT, guest_count INTEGER, notes TEXT, status TEXT DEFAULT 'planned', tax_rate REAL DEFAULT 0.0675, service_fee_pct REAL DEFAULT 20, min_spend REAL, space TEXT, service_style TEXT, service_hours REAL, bar_mode TEXT, bar_amount REAL, bar_notes TEXT, share_token TEXT, share_expires_at TEXT, share_revoked_at TEXT, location_id TEXT DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')) )
table|beo_line_items|CREATE TABLE beo_line_items ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, sort_order INTEGER DEFAULT 0, item_name TEXT NOT NULL, category TEXT, unit_cost REAL NOT NULL DEFAULT 0, quantity REAL NOT NULL DEFAULT 1, created_at TEXT DEFAULT (datetime('now')), prep_notes TEXT, secondary_prep_notes TEXT, order_items_notes TEXT, order_time TEXT, group_note TEXT, course_id INTEGER REFERENCES beo_courses(id) ON DELETE SET NULL, FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|beo_prep_history|CREATE TABLE beo_prep_history ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', client TEXT, event_date TEXT, -- ISO YYYY-MM-DD event_file TEXT, -- source xlsx filename if known type TEXT, -- 'Main Item' | 'Secondary Prep' | 'Special Sauce' | … item TEXT NOT NULL, amount_qty TEXT, -- numeric or descriptive (kept as text) prep_day TEXT, pre_prep_notes TEXT, plating_notes TEXT, source TEXT NOT NULL, -- e.g. 'master_workbook_2026-04-18' imported_at TEXT DEFAULT (datetime('now')) )
table|beo_prep_tasks|CREATE TABLE beo_prep_tasks ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, task TEXT NOT NULL, due_date TEXT, done INTEGER DEFAULT 0, sort_order INTEGER DEFAULT 0, location_id TEXT DEFAULT 'default', FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|beo_run_of_show|CREATE TABLE beo_run_of_show ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, show_time TEXT, note TEXT NOT NULL, sort_order INTEGER DEFAULT 0, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|beo_signatures|CREATE TABLE beo_signatures ( id INTEGER PRIMARY KEY AUTOINCREMENT, event_id INTEGER NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', signed_name TEXT NOT NULL, signed_at TEXT NOT NULL DEFAULT (datetime('now')), ip_addr TEXT, user_agent TEXT, FOREIGN KEY (event_id) REFERENCES beo_events(id) ON DELETE CASCADE )
table|bom_lines|CREATE TABLE bom_lines ( id INTEGER PRIMARY KEY AUTOINCREMENT, recipe_id TEXT NOT NULL, ingredient TEXT, qty REAL, unit TEXT, sub_recipe TEXT, vendor_ingredient TEXT, map_status TEXT, vendor TEXT, pack_price REAL, pack_size REAL, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')) , yield_pct REAL, loss_factor REAL, master_id TEXT)
table|box_office_lines|CREATE TABLE box_office_lines ( id INTEGER PRIMARY KEY AUTOINCREMENT, show_id INTEGER NOT NULL REFERENCES shows(id), location_id TEXT NOT NULL DEFAULT 'default', source TEXT NOT NULL CHECK (source IN ('dice','walkup','comp','will_call','guestlist')), ticket_class TEXT, qty INTEGER NOT NULL DEFAULT 1, face_price REAL, fees REAL, external_ref TEXT, scanned_at TEXT, notes TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|cleaning_log|CREATE TABLE cleaning_log ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', schedule_id INTEGER, area TEXT NOT NULL, task TEXT NOT NULL, completed_at TEXT NOT NULL, cook_id TEXT, verified_by_cook_id TEXT, notes TEXT, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (schedule_id) REFERENCES cleaning_schedule(id) ON DELETE SET NULL )
table|cleaning_schedule|CREATE TABLE cleaning_schedule ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', area TEXT NOT NULL, task TEXT NOT NULL, frequency TEXT NOT NULL, last_done TEXT, next_due TEXT, notes TEXT, active INTEGER DEFAULT 1, created_at TEXT DEFAULT (datetime('now')) , archived_at TEXT)
table|cloud_bridge_outbox|CREATE TABLE cloud_bridge_outbox ( id INTEGER PRIMARY KEY AUTOINCREMENT, table_name TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', rows_json TEXT NOT NULL, attempts INTEGER NOT NULL DEFAULT 0, last_error TEXT, dead_letter INTEGER NOT NULL DEFAULT 0, enqueued_at TEXT NOT NULL DEFAULT (datetime('now')), claimed_at TEXT, -- Audit H6 (2026-05-14): per-process claim owner. Set by claim() -- to lib/cloudBridgeQueue::OWNER (a UUID generated at module -- load). releaseAllClaimedRows() filters by this so a graceful -- shutdown only releases rows THIS process is holding — never -- yanks an in-flight claim out from under another drainer -- running in a different process (e.g. the standalone -- scripts/cloud-bridge-drainer.mjs alongside the in-process -- drainer from instrumentation.ts). sweepStaleClaims still -- ignores ownership (it's a time-based recovery for crashed -- holders, where the original owner is by definition gone). claim_owner TEXT )
table|cooling_log|CREATE TABLE cooling_log ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', item TEXT NOT NULL, station_id TEXT, started_at TEXT NOT NULL, start_reading_f REAL, stage1_at TEXT, stage1_reading_f REAL, stage2_at TEXT, stage2_reading_f REAL, status TEXT NOT NULL DEFAULT 'in_progress' CHECK(status IN ('in_progress','ok','breach')), breach_reason TEXT, corrective_action TEXT, cook_id TEXT, closed_by_cook_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|date_marks|CREATE TABLE date_marks ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', item TEXT NOT NULL, batch_ref TEXT, prepared_on TEXT NOT NULL, discard_on TEXT NOT NULL, discarded_at TEXT, discarded_by_cook_id TEXT, discard_reason TEXT, cook_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|dining_tables|CREATE TABLE dining_tables ( id TEXT NOT NULL, -- e.g. 'T1', 'T2', 'BAR-3' name TEXT NOT NULL, -- display label, e.g. 'Window 4' capacity INTEGER NOT NULL DEFAULT 2, x REAL NOT NULL DEFAULT 0, y REAL NOT NULL DEFAULT 0, w REAL NOT NULL DEFAULT 1, h REAL NOT NULL DEFAULT 1, status TEXT NOT NULL DEFAULT 'open' CHECK(status IN ('open','seated','dirty','closed')), notes TEXT, location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (location_id, id) )
table|dish_components|CREATE TABLE dish_components ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', dish_name TEXT NOT NULL, component_type TEXT NOT NULL DEFAULT 'recipe' CHECK(component_type IN ('recipe', 'vendor_item')), recipe_slug TEXT, vendor_ingredient TEXT, qty_per_serving REAL NOT NULL, unit TEXT NOT NULL, notes TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), CHECK ( (component_type = 'recipe' AND recipe_slug IS NOT NULL AND vendor_ingredient IS NULL) OR (component_type = 'vendor_item' AND vendor_ingredient IS NOT NULL AND recipe_slug IS NULL) ) )
table|dish_coverage_snapshots|CREATE TABLE dish_coverage_snapshots ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', total_dishes INTEGER, covered_dishes INTEGER, coverage_pct REAL, uncovered_dishes TEXT, created_by TEXT, snapshot_at TEXT DEFAULT (datetime('now')) )
table|eighty_six|CREATE TABLE eighty_six ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, station_id TEXT, item TEXT NOT NULL, kind TEXT DEFAULT 'item', reason TEXT, quantity TEXT, cook_id TEXT, resolved_at TEXT, resolved_by TEXT, created_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' )
table|employee_health_acknowledgments|CREATE TABLE employee_health_acknowledgments ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, policy_version TEXT NOT NULL, document_path TEXT, signed_on TEXT NOT NULL, created_at TEXT DEFAULT (datetime('now')) )
table|entities_employees|CREATE TABLE entities_employees ( uuid TEXT PRIMARY KEY, display_name TEXT NOT NULL, primary_email TEXT, primary_phone TEXT, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|entities_events|CREATE TABLE entities_events ( uuid TEXT PRIMARY KEY, display_name TEXT NOT NULL, event_date TEXT, event_time TEXT, venue TEXT, headliner TEXT, guest_count INTEGER, status TEXT NOT NULL DEFAULT 'planned' CHECK(status IN ('planned','confirmed','cancelled','completed')), location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|entities_ingredients|CREATE TABLE entities_ingredients ( uuid TEXT PRIMARY KEY, display_name TEXT NOT NULL, ingredient_key TEXT NOT NULL, category TEXT, default_unit TEXT, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE(ingredient_key) )
table|entities_menu_items|CREATE TABLE entities_menu_items ( uuid TEXT PRIMARY KEY, display_name TEXT NOT NULL, category TEXT, base_price REAL, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|entities_purchase_orders|CREATE TABLE entities_purchase_orders ( uuid TEXT PRIMARY KEY, vendor_uuid TEXT NOT NULL REFERENCES entities_vendors(uuid), po_number TEXT, ordered_at TEXT, expected_at TEXT, received_at TEXT, status TEXT NOT NULL DEFAULT 'open' CHECK(status IN ('open','sent','received','cancelled','closed')), total_amount REAL, location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|entities_recipes|CREATE TABLE entities_recipes ( uuid TEXT PRIMARY KEY, slug TEXT NOT NULL, display_name TEXT NOT NULL, yield_qty REAL, yield_unit TEXT, category TEXT, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE(slug, location_id) )
table|entities_vendors|CREATE TABLE entities_vendors ( uuid TEXT PRIMARY KEY, display_name TEXT NOT NULL, category TEXT, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|equipment_maintenance_schedule|CREATE TABLE equipment_maintenance_schedule ( id INTEGER PRIMARY KEY AUTOINCREMENT, equipment_id INTEGER NOT NULL, task TEXT NOT NULL, frequency TEXT NOT NULL, last_done TEXT, next_due TEXT, notes TEXT, location_id TEXT DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (equipment_id) REFERENCES equipment(id) ON DELETE CASCADE )
table|equipment_maintenance|CREATE TABLE equipment_maintenance ( id INTEGER PRIMARY KEY AUTOINCREMENT, equipment_id INTEGER NOT NULL, service_date TEXT NOT NULL, type TEXT NOT NULL, cost REAL, notes TEXT, receipt_reference TEXT, cook_id TEXT, location_id TEXT DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (equipment_id) REFERENCES equipment(id) ON DELETE CASCADE )
table|equipment_parts|CREATE TABLE equipment_parts ( id INTEGER PRIMARY KEY AUTOINCREMENT, equipment_id INTEGER NOT NULL, part_number TEXT NOT NULL, description TEXT, vendor TEXT, unit_price REAL, qty_on_hand REAL, last_ordered TEXT, last_order_ref TEXT, notes TEXT, location_id TEXT DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (equipment_id) REFERENCES equipment(id) ON DELETE CASCADE )
table|equipment|CREATE TABLE equipment ( id INTEGER PRIMARY KEY AUTOINCREMENT, name TEXT NOT NULL, category TEXT NOT NULL, make_model TEXT, serial_number TEXT, purchase_date TEXT, warranty_expiration TEXT, purchase_cost REAL, status TEXT DEFAULT 'active', location_id TEXT DEFAULT 'default' , model_number TEXT, vendor TEXT, vendor_order_ref TEXT, manual_path TEXT, notes TEXT)
table|external_ids|CREATE TABLE external_ids ( id INTEGER PRIMARY KEY AUTOINCREMENT, entity_type TEXT NOT NULL CHECK(entity_type IN ('employee','vendor','menu_item','recipe','ingredient', 'purchase_order','event')), entity_uuid TEXT NOT NULL, source_system TEXT NOT NULL, external_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', metadata_json TEXT, first_seen_at TEXT NOT NULL DEFAULT (datetime('now')), last_seen_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE(source_system, external_id, location_id, entity_type) )
table|gold_stars|CREATE TABLE gold_stars ( id INTEGER PRIMARY KEY AUTOINCREMENT, cook_name TEXT NOT NULL, reason TEXT NOT NULL, stars INTEGER DEFAULT 1, awarded_date TEXT DEFAULT (date('now')), location_id TEXT DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), deleted_at TEXT, deleted_by TEXT )
table|idempotency_keys|CREATE TABLE idempotency_keys ( key TEXT PRIMARY KEY, method TEXT NOT NULL, path TEXT NOT NULL, request_hash TEXT NOT NULL, response_status INTEGER NOT NULL, response_body TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT (datetime('now')) , status TEXT NOT NULL DEFAULT 'complete')
table|ingest_runs|CREATE TABLE ingest_runs ( id INTEGER PRIMARY KEY AUTOINCREMENT, kind TEXT NOT NULL, -- 'costing' | 'analytics' | 'unified' | 'toast' | ... started_at TEXT NOT NULL, -- ISO 8601 via datetime('now','subsec') finished_at TEXT, -- NULL while running rows_in INTEGER, rows_out INTEGER, status TEXT -- 'ok' | 'partial' | 'failed' | 'running' )
table|ingredient_densities|CREATE TABLE ingredient_densities ( ingredient_key TEXT PRIMARY KEY, g_per_ml REAL NOT NULL, source TEXT CHECK (source IS NULL OR source IN ('seed', 'measured', 'vendor')), updated_at TEXT DEFAULT (datetime('now')) )
table|ingredient_maps|CREATE TABLE ingredient_maps ( id INTEGER PRIMARY KEY AUTOINCREMENT, recipe_ingredient TEXT NOT NULL, vendor_ingredient TEXT, status TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')) )
table|ingredient_masters|CREATE TABLE ingredient_masters ( master_id TEXT PRIMARY KEY, -- slug: "ketchup_heinz_1gal" canonical_name TEXT NOT NULL, category TEXT, preferred_vendor TEXT, quality_locked INTEGER NOT NULL DEFAULT 0, quality_lock_reason TEXT, last_reviewed TEXT )
table|ingredient_unit_weights|CREATE TABLE ingredient_unit_weights ( ingredient_key TEXT NOT NULL, unit TEXT NOT NULL, -- canonical count unit (post-normalize_unit) g_per_unit REAL NOT NULL, -- grams per 1 of the count unit above source TEXT CHECK (source IS NULL OR source IN ('seed', 'measured', 'vendor')), updated_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (ingredient_key, unit) )
table|ingredient_yields|CREATE TABLE ingredient_yields ( ingredient_key TEXT PRIMARY KEY, -- same normalized form as ingredient_densities yield_pct REAL NOT NULL, -- fraction 0..1 (e.g. 0.85 for 85% trim yield) loss_factor REAL, -- cooking-shrinkage fraction 0..1; NULL if not applicable source TEXT NOT NULL CHECK (source IN ('book_of_yields', 'lariat_measured', 'seed')), notes TEXT, -- provenance / edge-case detail updated_at TEXT DEFAULT (datetime('now')) )
table|inventory_count_lines|CREATE TABLE inventory_count_lines ( id INTEGER PRIMARY KEY AUTOINCREMENT, count_id INTEGER NOT NULL REFERENCES inventory_counts(id) ON DELETE CASCADE, vendor TEXT, ingredient TEXT NOT NULL, sku TEXT NOT NULL DEFAULT '', on_hand_qty REAL, unit TEXT, par_qty REAL, par_unit TEXT, note TEXT, counted_by TEXT, counted_at TEXT DEFAULT (datetime('now')), location_id TEXT NOT NULL DEFAULT 'default', UNIQUE(count_id, ingredient, sku) )
table|inventory_counts|CREATE TABLE inventory_counts ( id INTEGER PRIMARY KEY AUTOINCREMENT, count_date TEXT NOT NULL, label TEXT, opened_at TEXT DEFAULT (datetime('now')), closed_at TEXT, cook_id TEXT, location_id TEXT NOT NULL DEFAULT 'default' )
table|inventory_par|CREATE TABLE inventory_par ( id INTEGER PRIMARY KEY AUTOINCREMENT, vendor TEXT, ingredient TEXT NOT NULL, sku TEXT NOT NULL DEFAULT '', par_qty REAL, par_unit TEXT, pack_size TEXT, pack_unit TEXT, category TEXT, note TEXT, location_id TEXT NOT NULL DEFAULT 'default', updated_at TEXT DEFAULT (datetime('now')), UNIQUE(location_id, ingredient, sku) )
table|inventory_updates|CREATE TABLE inventory_updates ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, station_id TEXT, item TEXT NOT NULL, master_id TEXT, delta TEXT, direction TEXT, note TEXT, cook_id TEXT, sync_source_host TEXT, sync_source_started_at TEXT, sync_source_pk TEXT, created_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' , receiving_log_id INTEGER REFERENCES receiving_log(id))
table|kds_ticket_lines|CREATE TABLE kds_ticket_lines ( id TEXT PRIMARY KEY, ticket_id TEXT NOT NULL REFERENCES kds_tickets(id) ON DELETE CASCADE, sort_order INTEGER NOT NULL DEFAULT 0, item_name TEXT NOT NULL, quantity INTEGER NOT NULL CHECK (quantity >= 1), station TEXT NOT NULL, modifiers TEXT )
table|kds_ticket_states|CREATE TABLE kds_ticket_states ( ticket_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', bumped_at TEXT NOT NULL, bumped_station TEXT, bumped_pin_hash TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (ticket_id, location_id) )
table|kds_tickets|CREATE TABLE kds_tickets ( id TEXT PRIMARY KEY, location_id TEXT NOT NULL DEFAULT 'default', order_number TEXT NOT NULL, placed_at TEXT NOT NULL, destination TEXT, bumped_at TEXT, created_by_cook_id TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|lari_conversation_turns|CREATE TABLE lari_conversation_turns ( schemaVersion TEXT NOT NULL DEFAULT 'lari_conversation_turn_v1' CHECK(schemaVersion = 'lari_conversation_turn_v1'), id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL, cook_id TEXT NOT NULL, conversation_session_id TEXT NOT NULL, user_content TEXT NOT NULL, assistant_content TEXT NOT NULL, manager_tier INTEGER NOT NULL DEFAULT 0 CHECK(manager_tier IN (0, 1)), created_at TEXT NOT NULL DEFAULT (datetime('now')), expires_at TEXT NOT NULL )
table|line_check_entries|CREATE TABLE line_check_entries ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, station_id TEXT NOT NULL, item TEXT NOT NULL, status TEXT NOT NULL CHECK(status IN ('pass','fail','na')), par TEXT, have TEXT, need TEXT, note TEXT, cook_id TEXT, -- F15 (FDA §3-301.11): NULL = item doesn't touch RTE food; -- 0 = glove-change required but not yet attested; -- 1 = cook has attested fresh gloves for this line-check row. glove_change_attested INTEGER, created_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' )
table|locations|CREATE TABLE locations ( id TEXT PRIMARY KEY, name TEXT NOT NULL, created_at TEXT DEFAULT (datetime('now')) , capacity INTEGER, tax_rate REAL DEFAULT 0.0675, service_fee_pct REAL DEFAULT 20, phone TEXT, address TEXT)
table|manager_pin_users|CREATE TABLE manager_pin_users ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', name TEXT NOT NULL, pin_hash TEXT NOT NULL, role TEXT NOT NULL DEFAULT 'manager' CHECK(role IN ('manager','owner')), is_active INTEGER NOT NULL DEFAULT 1 CHECK(is_active IN (0,1)), created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), disabled_at TEXT )
table|margin_snapshots|CREATE TABLE margin_snapshots ( id INTEGER PRIMARY KEY AUTOINCREMENT, item_name TEXT NOT NULL, net_sales REAL, cost_per_unit REAL, margin_pct REAL, popularity REAL, quadrant TEXT, snapshot_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' )
table|order_guide_items|CREATE TABLE order_guide_items ( id INTEGER PRIMARY KEY AUTOINCREMENT, ingredient TEXT NOT NULL, base_qty REAL, unit TEXT, vendor TEXT, unit_price REAL, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')), -- 1 = row holds a recipe-derived placeholder cost (no real vendor -- invoice yet) and MUST be ignored by the costing bridge. Backfill -- script scripts/flag-placeholder-order-guide.mjs stamps it for -- known bad rows; ingest pipelines never set it to 1. is_placeholder INTEGER DEFAULT 0 )
table|pack_size_changes|CREATE TABLE pack_size_changes ( id INTEGER PRIMARY KEY AUTOINCREMENT, vendor TEXT NOT NULL, sku TEXT NOT NULL, prev_pack TEXT, -- e.g. "6x#10" new_pack TEXT, prev_price REAL, new_price REAL, detected_at TEXT DEFAULT (datetime('now')), acknowledged INTEGER DEFAULT 0 )
table|paid_sick_leave_balances|CREATE TABLE paid_sick_leave_balances ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, accrual_year INTEGER NOT NULL, hours_accrued REAL NOT NULL DEFAULT 0, hours_used REAL NOT NULL DEFAULT 0, cap_hours REAL NOT NULL DEFAULT 48, carryover_hours REAL NOT NULL DEFAULT 0, last_accrued_on TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), UNIQUE(location_id, cook_id, accrual_year) )
table|peer_trust|CREATE TABLE peer_trust ( pubkey_hex TEXT PRIMARY KEY, fingerprint TEXT NOT NULL UNIQUE, label TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')), last_seen_at TEXT, revoked INTEGER NOT NULL DEFAULT 0 )
table|performance_reviews|CREATE TABLE performance_reviews ( id INTEGER PRIMARY KEY AUTOINCREMENT, cook_name TEXT NOT NULL, cook_uuid TEXT, review_date TEXT NOT NULL, punctuality_score INTEGER, technique_score INTEGER, speed_score INTEGER, notes TEXT, reviewer_name TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|pest_control_log|CREATE TABLE pest_control_log ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', entry_type TEXT NOT NULL CHECK(entry_type IN ('service_visit','sighting','trap_check')), vendor TEXT, technician TEXT, findings TEXT, pest TEXT, severity TEXT CHECK(severity IS NULL OR severity IN ('low','medium','high')), corrective_action TEXT, report_path TEXT, cook_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|prep_par|CREATE TABLE prep_par ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', station_id TEXT NOT NULL DEFAULT '', recipe_slug TEXT NOT NULL DEFAULT '', ingredient TEXT NOT NULL DEFAULT '', target_qty REAL, unit TEXT, sort_order INTEGER DEFAULT 0, note TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), UNIQUE(location_id, station_id, recipe_slug, ingredient), CHECK (recipe_slug <> '' OR ingredient <> '') )
table|prep_tasks|CREATE TABLE prep_tasks ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, station_id TEXT, task TEXT NOT NULL, qty TEXT, recipe_slug TEXT, notes TEXT, priority INTEGER DEFAULT 0, assigned_cook_id TEXT, status TEXT NOT NULL DEFAULT 'todo' CHECK(status IN ('todo','in_progress','done','skipped')), started_at TEXT, done_at TEXT, done_by TEXT, source TEXT DEFAULT 'manual', source_ref TEXT, sort_order INTEGER DEFAULT 0, location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')) )
table|preshift_notes|CREATE TABLE preshift_notes ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', shift_date TEXT NOT NULL, service_label TEXT, body TEXT NOT NULL, author_cook_id TEXT, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')), UNIQUE(location_id, shift_date, service_label) )
table|prism_events|CREATE TABLE prism_events ( prism_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', event_uuid TEXT, display_name TEXT, event_date TEXT, doors_at TEXT, show_at TEXT, venue TEXT, headliner TEXT, supports_json TEXT, ticket_count INTEGER, capacity INTEGER, status TEXT, raw_json TEXT, ingested_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (prism_id, location_id) )
table|receiving_log|CREATE TABLE receiving_log ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', vendor TEXT NOT NULL, invoice_ref TEXT, category TEXT NOT NULL, item TEXT, vendor_sku TEXT, master_id TEXT, match_status TEXT DEFAULT 'not_attempted', match_reason TEXT, reading_f REAL, required_max_f REAL, package_ok INTEGER, -- 1 = intact, 0 = compromised, NULL = unrecorded (legacy) expiration_date TEXT, -- YYYY-MM-DD; NULL when not printed on the case status TEXT NOT NULL CHECK(status IN ('accepted','rejected','accepted_with_note')), rejection_reason TEXT, shellstock_tag_ref TEXT, cook_id TEXT, sync_source_host TEXT, sync_source_started_at TEXT, sync_source_pk TEXT, created_at TEXT DEFAULT (datetime('now')) , received_qty REAL, received_unit TEXT)
table|recipe_costs|CREATE TABLE recipe_costs ( id INTEGER PRIMARY KEY AUTOINCREMENT, recipe_id TEXT NOT NULL, recipe_name TEXT, category TEXT, yield REAL, yield_unit TEXT, batch_cost REAL, cost_per_yield_unit REAL, costed_lines INTEGER, total_lines INTEGER, interpretations INTEGER, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')), UNIQUE(location_id, recipe_id) )
table|recipe_photos|CREATE TABLE recipe_photos ( id INTEGER PRIMARY KEY AUTOINCREMENT, recipe_slug TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', original_name TEXT NOT NULL, stored_path TEXT NOT NULL, mime TEXT NOT NULL, size_bytes INTEGER NOT NULL, caption TEXT, uploaded_by_cook_id TEXT, uploaded_at TEXT NOT NULL DEFAULT (datetime('now')), deleted_at TEXT , is_hero INTEGER NOT NULL DEFAULT 0)
table|replay_checkpoints|CREATE TABLE replay_checkpoints ( peer_id TEXT NOT NULL, feed_scope TEXT NOT NULL DEFAULT 'local', last_op_rowid INTEGER NOT NULL DEFAULT 0, updated_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (peer_id, feed_scope) )
table|reservations|CREATE TABLE reservations ( id INTEGER PRIMARY KEY AUTOINCREMENT, party_name TEXT NOT NULL, party_size INTEGER NOT NULL, reservation_at TEXT NOT NULL, -- 'YYYY-MM-DD HH:MM' local status TEXT NOT NULL DEFAULT 'booked' CHECK(status IN ('booked','seated','completed','cancelled','no_show')), table_id TEXT, -- soft FK to tables.id once that exists phone TEXT, email TEXT, notes TEXT, source TEXT DEFAULT 'manual', -- 'manual', 'opentable', 'phone', etc. source_ref TEXT, seated_at TEXT, completed_at TEXT, cook_id TEXT, -- whoever booked or last touched it location_id TEXT NOT NULL DEFAULT 'default', created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')) )
table|sales_depletion_runs|CREATE TABLE sales_depletion_runs ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL, period_label TEXT NOT NULL, shift_date TEXT NOT NULL, sales_rows_processed INTEGER NOT NULL DEFAULT 0, depletions_written INTEGER NOT NULL DEFAULT 0, unresolved_dish_count INTEGER NOT NULL DEFAULT 0, applied_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|sales_lines|CREATE TABLE sales_lines ( id INTEGER PRIMARY KEY AUTOINCREMENT, period_label TEXT, item_name TEXT NOT NULL, quantity_sold REAL, net_sales REAL, source TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')) , service_date TEXT, service_period TEXT)
table|sanitizer_checks|CREATE TABLE sanitizer_checks ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', station_id TEXT, point_label TEXT NOT NULL, chemistry TEXT NOT NULL CHECK(chemistry IN ('chlorine','quat','iodine','other')), concentration_ppm REAL NOT NULL, required_min_ppm REAL, required_max_ppm REAL, water_temp_f REAL, status TEXT NOT NULL CHECK(status IN ('ok','low','high')), corrective_action TEXT, cook_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|schema_migrations|CREATE TABLE schema_migrations ( version INTEGER PRIMARY KEY, applied_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|sds_registry|CREATE TABLE sds_registry ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', product_name TEXT NOT NULL, manufacturer TEXT, hazard_class TEXT, storage_location TEXT, pdf_path TEXT, url TEXT, last_reviewed TEXT, active INTEGER DEFAULT 1, notes TEXT, created_at TEXT DEFAULT (datetime('now')) , archived_at TEXT)
table|service_hours|CREATE TABLE service_hours ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', day_of_week INTEGER NOT NULL, opens_at TEXT, closes_at TEXT, service_label TEXT, notes TEXT, active INTEGER DEFAULT 1, created_at TEXT DEFAULT (datetime('now')), archived_at TEXT, UNIQUE(location_id, day_of_week, service_label) )
table|sevenshifts_shifts|CREATE TABLE sevenshifts_shifts ( seven_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', user_seven_id TEXT, employee_uuid TEXT, role_id TEXT, department_id TEXT, start_at TEXT, end_at TEXT, published INTEGER, deleted INTEGER NOT NULL DEFAULT 0 CHECK(deleted IN (0,1)), raw_json TEXT, ingested_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (seven_id, location_id) )
table|sevenshifts_time_punches|CREATE TABLE sevenshifts_time_punches ( seven_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', user_seven_id TEXT, employee_uuid TEXT, role_id TEXT, clocked_in_at TEXT, clocked_out_at TEXT, hours_worked REAL, approved INTEGER, raw_json TEXT, ingested_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (seven_id, location_id) )
table|sevenshifts_users|CREATE TABLE sevenshifts_users ( seven_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', employee_uuid TEXT, first_name TEXT, last_name TEXT, preferred_name TEXT, email TEXT, phone TEXT, employee_id TEXT, role_ids_json TEXT, hire_date TEXT, active INTEGER NOT NULL DEFAULT 1 CHECK(active IN (0,1)), raw_json TEXT, ingested_at TEXT NOT NULL DEFAULT (datetime('now')), PRIMARY KEY (seven_id, location_id) )
table|shift_breaks|CREATE TABLE shift_breaks ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, kind TEXT NOT NULL CHECK(kind IN ('meal','rest')), started_at TEXT NOT NULL, ended_at TEXT, duration_min REAL, waived INTEGER DEFAULT 0, waiver_ref TEXT, note TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|shift_pic|CREATE TABLE shift_pic ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', shift_slot TEXT NOT NULL CHECK(shift_slot IN ('open','mid','close','all_day')), cook_id TEXT NOT NULL, cfpm_cert_id INTEGER, started_at TEXT NOT NULL, ended_at TEXT, note TEXT, created_at TEXT DEFAULT (datetime('now')), FOREIGN KEY (cfpm_cert_id) REFERENCES staff_certifications(id) ON DELETE SET NULL )
table|show_deals|CREATE TABLE show_deals ( id INTEGER PRIMARY KEY AUTOINCREMENT, show_id INTEGER NOT NULL REFERENCES shows(id), location_id TEXT NOT NULL DEFAULT 'default', guarantee_cents INTEGER NOT NULL DEFAULT 0, vs_pct_after_costs REAL, costs_off_top_json TEXT NOT NULL DEFAULT '[]', buyout_cents INTEGER NOT NULL DEFAULT 0, notes TEXT, updated_at TEXT NOT NULL DEFAULT (datetime('now')), updated_by_cook_id TEXT, UNIQUE (show_id, location_id) )
table|shows_archive|CREATE TABLE shows_archive ( id INTEGER PRIMARY KEY, location_id TEXT NOT NULL DEFAULT 'default', band_name TEXT NOT NULL, show_date TEXT NOT NULL, era_year INTEGER, source_row INTEGER NOT NULL, ingested_at TEXT NOT NULL, ingest_run_id INTEGER NOT NULL REFERENCES ingest_runs(id) )
table|shows|CREATE TABLE shows ( id INTEGER PRIMARY KEY, location_id TEXT NOT NULL DEFAULT 'default', band_name TEXT NOT NULL, show_date TEXT NOT NULL, price REAL, door_tix TEXT, status_json TEXT NOT NULL DEFAULT '{}', source_row INTEGER NOT NULL, ingested_at TEXT NOT NULL, ingest_run_id INTEGER NOT NULL REFERENCES ingest_runs(id) )
table|sick_note_documents|CREATE TABLE sick_note_documents ( id INTEGER PRIMARY KEY AUTOINCREMENT, report_id INTEGER NOT NULL, location_id TEXT NOT NULL, file_path TEXT NOT NULL, kind TEXT NOT NULL, original_filename TEXT, uploaded_by TEXT, uploaded_at TEXT NOT NULL )
table|sick_worker_reports|CREATE TABLE sick_worker_reports ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, reported_by_pic_id TEXT, symptoms TEXT NOT NULL, diagnosed_illness TEXT, action TEXT NOT NULL CHECK(action IN ('excluded','restricted','monitor','none')), started_at TEXT NOT NULL, return_at TEXT, clearance_source TEXT, note TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|sound_scenes|CREATE TABLE sound_scenes ( id INTEGER PRIMARY KEY AUTOINCREMENT, show_id INTEGER NOT NULL REFERENCES shows(id), location_id TEXT NOT NULL DEFAULT 'default', scene_name TEXT NOT NULL, plot_json TEXT NOT NULL, spl_limit_db REAL, notes TEXT, saved_by_cook_id TEXT, saved_at TEXT NOT NULL DEFAULT (datetime('now')) )
table|specials_promotions|CREATE TABLE specials_promotions ( id INTEGER PRIMARY KEY AUTOINCREMENT, special_id TEXT NOT NULL, location_id TEXT NOT NULL DEFAULT 'default', menu_item_name TEXT NOT NULL, servings REAL NOT NULL DEFAULT 1, components_json TEXT NOT NULL DEFAULT '[]', promoted_at INTEGER NOT NULL, updated_at INTEGER NOT NULL )
table|specials|CREATE TABLE specials ( id TEXT PRIMARY KEY, location_id TEXT NOT NULL DEFAULT 'default', name TEXT NOT NULL, pantry_text TEXT NOT NULL DEFAULT '', prompt_text TEXT NOT NULL DEFAULT '', ai_answer TEXT NOT NULL DEFAULT '', ai_model TEXT NOT NULL DEFAULT '', cost_breakdown TEXT, cost_total REAL, scratch_notes TEXT NOT NULL DEFAULT '', sources TEXT, last_exported_at INTEGER, created_at INTEGER NOT NULL, updated_at INTEGER NOT NULL, archived_at INTEGER )
table|spend_monthly|CREATE TABLE spend_monthly ( id INTEGER PRIMARY KEY AUTOINCREMENT, month TEXT NOT NULL, shamrock_total_spend REAL, source TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')) )
table|spl_readings|CREATE TABLE spl_readings ( id INTEGER PRIMARY KEY AUTOINCREMENT, show_id INTEGER NOT NULL REFERENCES shows(id), location_id TEXT NOT NULL DEFAULT 'default', scene_id INTEGER REFERENCES sound_scenes(id), db_value REAL NOT NULL, taken_at TEXT NOT NULL DEFAULT (datetime('now')), taken_by_cook_id TEXT, notes TEXT )
table|staff_certifications|CREATE TABLE staff_certifications ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, cert_type TEXT NOT NULL CHECK(cert_type IN ('cfpm','food_handler','tips','allergen','other')), cert_label TEXT NOT NULL, issuer TEXT, cert_number TEXT, issued_on TEXT, expires_on TEXT, document_path TEXT, active INTEGER DEFAULT 1, created_at TEXT DEFAULT (datetime('now')), updated_at TEXT DEFAULT (datetime('now')) , archived_at TEXT)
table|staff_flags|CREATE TABLE staff_flags ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, flag TEXT NOT NULL, effective_from TEXT NOT NULL, effective_to TEXT, note TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|stage_setups|CREATE TABLE stage_setups ( id INTEGER PRIMARY KEY AUTOINCREMENT, show_id INTEGER NOT NULL REFERENCES shows(id), location_id TEXT NOT NULL DEFAULT 'default', room_config TEXT NOT NULL, run_of_show_json TEXT NOT NULL DEFAULT '[]', hospitality_rider_json TEXT NOT NULL DEFAULT '{}', tech_rider_json TEXT NOT NULL DEFAULT '{}', notes TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')), UNIQUE (show_id, location_id) )
table|station_signoffs|CREATE TABLE station_signoffs ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, station_id TEXT NOT NULL, cook_id TEXT NOT NULL, signoff_type TEXT NOT NULL DEFAULT 'self', created_at TEXT DEFAULT (datetime('now')), location_id TEXT DEFAULT 'default' )
table|sync_feed|CREATE TABLE sync_feed ( id INTEGER PRIMARY KEY AUTOINCREMENT, -- UUIDv7. Globally unique; idempotency key for replay. op_id TEXT NOT NULL UNIQUE, -- Source table on the originating host (e.g. 'cooling_log'). table_name TEXT NOT NULL, -- Multi-tenant scope; matches the source row's location_id. location_id TEXT NOT NULL DEFAULT 'default', -- Operation kind; see SyncOpKind in lib/syncFeed.ts. op_kind TEXT NOT NULL CHECK(op_kind IN ('insert','update','delete','delete-batch')), -- Stringified PK (or batch key for delete-batch). row_pk TEXT NOT NULL, -- JSON-encoded row body. '{}' for delete; rows-array payload for -- delete-batch envelopes. row_json TEXT NOT NULL, created_at TEXT NOT NULL DEFAULT (datetime('now')), -- Originating instance identity. Pair: (host, started_at) per -- lib/hubFailover.ts. source_host TEXT NOT NULL, source_started_at TEXT NOT NULL )
table|temp_log|CREATE TABLE temp_log ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', point_id TEXT NOT NULL, reading_f REAL NOT NULL, required_min_f REAL, required_max_f REAL, corrective_action TEXT, cook_id TEXT, -- Bundle G: optional thermometer id linking the reading to a -- probe calibration record (see thermometer_calibrations). Null -- means "no probe recorded" — reading is still persisted. probe_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|temp_pins|CREATE TABLE temp_pins ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', pin_hash TEXT NOT NULL UNIQUE, label TEXT NOT NULL, scopes_json TEXT NOT NULL, issued_by TEXT, issued_at TEXT NOT NULL DEFAULT (datetime('now')), expires_at TEXT NOT NULL, revoked_at TEXT )
table|thermometer_calibrations|CREATE TABLE thermometer_calibrations ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', thermometer_id TEXT NOT NULL, method TEXT NOT NULL CHECK(method IN ('ice_point','boiling_point','reference_probe')), before_reading_f REAL, after_reading_f REAL, passed INTEGER NOT NULL DEFAULT 0, action_taken TEXT, cook_id TEXT, calibrated_at TEXT NOT NULL, -- Per-probe calibration frequency override in days. NULL means -- "use the default 30-day schedule". A positive integer overrides -- the default for this probe (e.g. high-use probes every 14 days). frequency_days INTEGER, created_at TEXT DEFAULT (datetime('now')) )
table|tiktok_ideas|CREATE TABLE tiktok_ideas ( id INTEGER PRIMARY KEY, location_id TEXT NOT NULL DEFAULT 'default', idea TEXT NOT NULL, video_content TEXT, staff_needed TEXT, props TEXT, notes TEXT, source_row INTEGER NOT NULL, ingested_at TEXT NOT NULL, ingest_run_id INTEGER NOT NULL REFERENCES ingest_runs(id) )
table|tip_pool_distributions|CREATE TABLE tip_pool_distributions ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', pool_ref TEXT NOT NULL, cook_id TEXT NOT NULL, role TEXT, kind TEXT NOT NULL CHECK(kind IN ('tip_pool','service_charge','direct_tip')), amount_cents INTEGER NOT NULL, note TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|toast_sales_daily|CREATE TABLE toast_sales_daily ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, net_sales REAL, orders INTEGER, guests INTEGER, comparison_group INTEGER NOT NULL, date_range TEXT, source TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')), UNIQUE(shift_date, comparison_group, location_id) )
table|toast_sales_dow|CREATE TABLE toast_sales_dow ( id INTEGER PRIMARY KEY AUTOINCREMENT, day_of_week TEXT NOT NULL, net_sales REAL, orders INTEGER, guests INTEGER, comparison_group INTEGER NOT NULL, date_range TEXT, source TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')), UNIQUE(day_of_week, comparison_group, location_id) )
table|toast_sales_hour|CREATE TABLE toast_sales_hour ( id INTEGER PRIMARY KEY AUTOINCREMENT, hour_24 INTEGER NOT NULL, label TEXT NOT NULL, net_sales REAL, orders INTEGER, guests INTEGER, comparison_group INTEGER NOT NULL, date_range TEXT, source TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')), UNIQUE(hour_24, comparison_group, location_id) )
table|toast_subscription_invoice_lines|CREATE TABLE toast_subscription_invoice_lines ( id INTEGER PRIMARY KEY AUTOINCREMENT, invoice_no TEXT NOT NULL, invoice_date TEXT NOT NULL, -- denormalized for fast year/month rollups line_seq INTEGER NOT NULL, -- 1-based order within the invoice item TEXT NOT NULL, qty INTEGER NOT NULL, -- can be negative (credit lines) rate REAL NOT NULL, amount REAL NOT NULL, -- can be negative (credit lines) location_id TEXT NOT NULL DEFAULT 'default', UNIQUE(location_id, invoice_no, line_seq) )
table|toast_subscription_invoices|CREATE TABLE toast_subscription_invoices ( invoice_no TEXT NOT NULL, invoice_date TEXT NOT NULL, -- YYYY-MM-DD invoice_total REAL NOT NULL, line_count INTEGER NOT NULL, source_pdf TEXT, location_id TEXT NOT NULL DEFAULT 'default', ingested_at TEXT NOT NULL DEFAULT (datetime('now','subsec')), PRIMARY KEY (location_id, invoice_no) )
table|tphc_entries|CREATE TABLE tphc_entries ( id INTEGER PRIMARY KEY AUTOINCREMENT, shift_date TEXT NOT NULL, location_id TEXT DEFAULT 'default', station_id TEXT, item TEXT NOT NULL, batch_ref TEXT, started_at TEXT NOT NULL, cutoff_at TEXT NOT NULL, discarded_at TEXT, discard_reason TEXT, cook_id TEXT, created_at TEXT DEFAULT (datetime('now')) )
table|vendor_catch_weights|CREATE TABLE vendor_catch_weights ( vendor TEXT NOT NULL, sku TEXT NOT NULL, catalog_wt_lb REAL NOT NULL, tare_lb REAL, source TEXT, updated_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (vendor, sku) )
table|vendor_prices_history|CREATE TABLE vendor_prices_history ( id INTEGER PRIMARY KEY AUTOINCREMENT, run_id INTEGER, source_vendor_price_id INTEGER, ingredient TEXT NOT NULL, vendor TEXT, sku TEXT, pack_size REAL, pack_unit TEXT, pack_price REAL, unit_price REAL, category TEXT, yield_pct REAL, actual_received_lb REAL, reconciled_unit_price REAL, master_id TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT, snapshot_at TEXT DEFAULT (datetime('now','subsec')), snapshot_reason TEXT )
table|vendor_prices|CREATE TABLE vendor_prices ( id INTEGER PRIMARY KEY AUTOINCREMENT, ingredient TEXT NOT NULL, vendor TEXT, sku TEXT, pack_size REAL, pack_unit TEXT, pack_price REAL, unit_price REAL, category TEXT, location_id TEXT DEFAULT 'default', imported_at TEXT DEFAULT (datetime('now')) , yield_pct REAL, actual_received_lb REAL, reconciled_unit_price REAL, map_status TEXT, master_id TEXT)
table|wage_notices|CREATE TABLE wage_notices ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT DEFAULT 'default', cook_id TEXT NOT NULL, reason TEXT NOT NULL CHECK(reason IN ('hire','rate_change','annual','law_change','other')), wage_rate_cents INTEGER NOT NULL, pay_basis TEXT NOT NULL CHECK(pay_basis IN ('hourly','salary','commission','tipped')), tip_credit_cents INTEGER, document_path TEXT, signed_on TEXT NOT NULL, created_at TEXT DEFAULT (datetime('now')) )
table|waitlist_parties|CREATE TABLE waitlist_parties ( id INTEGER PRIMARY KEY AUTOINCREMENT, location_id TEXT NOT NULL DEFAULT 'default', party_name TEXT NOT NULL, party_size INTEGER NOT NULL, joined_at TEXT NOT NULL DEFAULT (datetime('now')), status TEXT NOT NULL DEFAULT 'waiting' CHECK(status IN ('waiting','seated','left')), seated_at TEXT, left_at TEXT, phone TEXT, notes TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')), updated_at TEXT NOT NULL DEFAULT (datetime('now')) )
